import{_ as e,a as o,b as r,c as t,d as i}from"./chunks/编辑配置.T0puvWjh.js";import{_ as l,o as n,c as d,a2 as s}from"./chunks/framework.DnrXFDHb.js";const C=JSON.parse('{"title":"Adicionar canal Telegram","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/upload/telegram.md","filePath":"pt-BR/upload/telegram.md","lastUpdated":1781962217000}'),c={name:"pt-BR/upload/telegram.md"};function p(m,a,h,b,g,u){return n(),d("div",null,[...a[0]||(a[0]=[s('<h1 id="adicionar-canal-telegram" tabindex="-1">Adicionar canal Telegram <a class="header-anchor" href="#adicionar-canal-telegram" aria-label="Permalink to &quot;Adicionar canal Telegram&quot;">​</a></h1><p>Para usar Telegram como armazenamento, crie um bot e adicione esse bot ao canal onde os arquivos serão salvos.</p><h2 id="o-que-preparar" tabindex="-1">O que preparar <a class="header-anchor" href="#o-que-preparar" aria-label="Permalink to &quot;O que preparar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Item</th><th>Uso</th></tr></thead><tbody><tr><td>Conta Telegram</td><td>Criar bot e canal</td></tr><tr><td><code>@BotFather</code></td><td>Criar o bot</td></tr><tr><td>Canal Telegram</td><td>Destino dos arquivos</td></tr><tr><td><code>@userinfobot</code></td><td>Obter o Chat ID do canal</td></tr></tbody></table><h2 id="criar-bot" tabindex="-1">Criar bot <a class="header-anchor" href="#criar-bot" aria-label="Permalink to &quot;Criar bot&quot;">​</a></h2><ol><li>Pesquise <code>@BotFather</code> no Telegram.</li><li>Abra o chat e envie <code>/newbot</code>.</li><li>Informe nome exibido e username. O username normalmente precisa terminar em <code>bot</code>.</li><li>Copie o Token retornado pelo BotFather.</li></ol><p><img src="'+e+'" alt="Bot Token" loading="lazy"></p><h2 id="criar-canal-de-armazenamento" tabindex="-1">Criar canal de armazenamento <a class="header-anchor" href="#criar-canal-de-armazenamento" aria-label="Permalink to &quot;Criar canal de armazenamento&quot;">​</a></h2><p>Crie um novo canal no Telegram. Ele pode ser público ou privado.</p><p><img src="'+o+'" alt="Criar canal" loading="lazy"></p><h2 id="adicionar-o-bot-ao-canal" tabindex="-1">Adicionar o bot ao canal <a class="header-anchor" href="#adicionar-o-bot-ao-canal" aria-label="Permalink to &quot;Adicionar o bot ao canal&quot;">​</a></h2><p>Nas configurações do canal, adicione o bot como membro ou administrador.</p><p><img src="'+r+'" alt="Adicionar bot ao canal" loading="lazy"></p><p>Para uploads mais estáveis, é melhor dar permissões de administrador.</p><h2 id="obter-chat-id" tabindex="-1">Obter Chat ID <a class="header-anchor" href="#obter-chat-id" aria-label="Permalink to &quot;Obter Chat ID&quot;">​</a></h2><ol><li>Pesquise <code>@userinfobot</code> no Telegram.</li><li>Clique em <code>Start</code>.</li><li>Escolha <code>Channel</code>.</li><li>Envie ao bot uma mensagem do canal alvo.</li><li>Copie o número exibido como <code>Id: -100...</code>.</li></ol><p><img src="'+t+'" alt="Obter Chat ID" loading="lazy"></p><h2 id="preencher-no-imgbed" tabindex="-1">Preencher no ImgBed <a class="header-anchor" href="#preencher-no-imgbed" aria-label="Permalink to &quot;Preencher no ImgBed&quot;">​</a></h2><p>Em Configurações de upload, escolha <code>Telegram</code>.</p><table tabindex="0"><thead><tr><th>Campo</th><th>Valor</th></tr></thead><tbody><tr><td>Nome do canal</td><td>Por exemplo <code>Telegram Main</code></td></tr><tr><td>Bot Token</td><td>Token do <code>@BotFather</code></td></tr><tr><td>Session ID / Chat ID</td><td>ID do canal que começa com <code>-100</code></td></tr><tr><td>Relay Proxy URL</td><td>Opcional, apenas se Telegram estiver instável</td></tr><tr><td>Observação</td><td>Opcional</td></tr></tbody></table><p><img src="'+i+`" alt="Configuração Telegram" loading="lazy"></p><h2 id="verificacao" tabindex="-1">Verificação <a class="header-anchor" href="#verificacao" aria-label="Permalink to &quot;Verificação&quot;">​</a></h2><ol><li>Salve o canal.</li><li>Envie uma imagem de teste.</li><li>Confira se ela aparece no canal do Telegram.</li><li>Abra o link do ImgBed.</li></ol><h2 id="fluxo-rapido" tabindex="-1">Fluxo rápido <a class="header-anchor" href="#fluxo-rapido" aria-label="Permalink to &quot;Fluxo rápido&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Criar bot com @BotFather</span></span>
<span class="line"><span>-&gt; Copiar Bot Token</span></span>
<span class="line"><span>-&gt; Criar canal Telegram</span></span>
<span class="line"><span>-&gt; Adicionar bot ao canal e dar permissões</span></span>
<span class="line"><span>-&gt; Obter Chat ID -100 com @userinfobot</span></span>
<span class="line"><span>-&gt; Preencher Bot Token e Chat ID no ImgBed</span></span>
<span class="line"><span>-&gt; Salvar e testar upload</span></span></code></pre></div><h2 id="referencias" tabindex="-1">Referências <a class="header-anchor" href="#referencias" aria-label="Permalink to &quot;Referências&quot;">​</a></h2><ol><li>Telegram Bot: <a href="https://core.telegram.org/bots" target="_blank" rel="noreferrer">https://core.telegram.org/bots</a></li><li>Telegram Bot API: <a href="https://core.telegram.org/bots/api" target="_blank" rel="noreferrer">https://core.telegram.org/bots/api</a></li></ol>`,27)])])}const q=l(c,[["render",p]]);export{C as __pageData,q as default};
